data:{"type": "TOOL_CALL_RESULT", "raw_event": {"name": "log_analysis", "raw_event_data": null}, "message_id": "ce416c979d2f479496ba45e96e56a3fe", "tool_call_id": "call_b20a8d6449884031bdd1ff08", "content": "The content of /istorm-aiagent-flow/app/prodline/mcp_server/sre/mcp_server_elasticsearch/server.py:\n```\n1: #!/usr/bin/env python3\n2: \"\"\"\n3: MCP Server \u2014 Elasticsearch \u65e5\u5fd7\u641c\u7d22\u5de5\u5177\n4: \n5: \u63d0\u4f9b\u5168\u6587\u641c\u7d22\u3001ERROR \u65e5\u5fd7\u641c\u7d22\u3001\u65e5\u5fd7\u8ba1\u6570\u3001\u9519\u8bef\u805a\u5408\u3001\u96c6\u7fa4\u5065\u5eb7\u3001\u7d22\u5f15\u5217\u8868\u7b49\u5de5\u5177\u3002\n6: \u4f5c\u4e3a\u5b50\u6a21\u5757\u88ab server.py \u7f51\u5173\u5bfc\u5165\uff0c\u901a\u8fc7 SSE \u4f20\u8f93\u5bf9\u5916\u670d\u52a1\u3002\n7: \"\"\"\n8: \n9: import json\n10: import os\n11: \n12: import httpx\n13: from mcp.server.fastmcp import FastMCP\n14: \n15: ES_URL = os.environ.get(\"ES_URL\", \"http://10.1.80.20:30092\")\n16: NAMESPACE = os.environ.get(\"NAMESPACE\", \"ops-stack\")\n17: INDEX_PATTERN = \"filebeat-*\"\n18: \n19: mcp = FastMCP(\n20:     \"sre-elasticsearch\",\n21:     instructions=\"Elasticsearch \u65e5\u5fd7\u641c\u7d22\u5de5\u5177\u670d\u52a1\u5668\uff0c\u63d0\u4f9b\u5168\u6587\u641c\u7d22\u3001\u9519\u8bef\u805a\u5408\u3001\u96c6\u7fa4\u5065\u5eb7\u7b49\u80fd\u529b\",\n22: )\n23: \n24: \n25: def _es_post(path: str, body: dict) -> dict:\n26:     \"\"\"\u5411 Elasticsearch \u53d1\u9001 POST \u8bf7\u6c42\"\"\"\n27:     url = f\"{ES_URL}/{path}\"\n28:     resp = httpx.post(\n29:         url,\n30:         json=body,\n31:         headers={\"Content-Type\": \"application/json\"},\n32:         timeout=30,\n33:     )\n34:     resp.raise_for_status()\n35:     return resp.json()\n36: \n37: \n38: def _es_get(path: str) -> str:\n39:     \"\"\"\u5411 Elasticsearch \u53d1\u9001 GET \u8bf7\u6c42\"\"\"\n40:     url = f\"{ES_URL}/{path}\"\n41:     resp = httpx.get(url, timeout=30)\n42:     resp.raise_for_status()\n43:     # \u6709\u4e9b ES \u7aef\u70b9\u8fd4\u56de\u7eaf\u6587\u672c\n44:     content_type = resp.headers.get(\"content-type\", \"\")\n45:     if \"application/json\" in content_type:\n46:         return json.dumps(resp.json(), indent=2, ensure_ascii=False)\n47:     return resp.text\n48: \n49: \n50: @mcp.tool()\n51: def es_search_logs(\n52:     keyword: str,\n53:     size: int = 20,\n54:     duration: str = \"15m\",\n55:     namespace: str = \"\",\n56: ) -> str:\n57:     \"\"\"\u5168\u6587\u641c\u7d22\u65e5\u5fd7\uff0c\u6309\u65f6\u95f4\u5012\u5e8f\u8fd4\u56de\u5339\u914d\u7ed3\u679c\u3002\n58: \n59:     Args:\n60:         keyword: \u641c\u7d22\u5173\u952e\u5b57\uff0c\u652f\u6301 Lucene \u67e5\u8be2\u8bed\u6cd5\uff08\u5982 \"error AND timeout\"\uff09\n61:         size: \u8fd4\u56de\u6761\u6570\uff0c\u9ed8\u8ba4 20\n62:         duration: \u56de\u6eaf\u65f6\u957f\uff08\u5982 15m/1h/6h\uff09\uff0c\u9ed8\u8ba4 15m\n63:         namespace: K8s \u547d\u540d\u7a7a\u95f4\u8fc7\u6ee4\uff0c\u9ed8\u8ba4 ops-stack\n64:     \"\"\"\n65:     ns = namespace or NAMESPACE\n66:     body = {\n67:         \"size\": size,\n68:         \"sort\": [{\"@timestamp\": \"desc\"}],\n69:         \"query\": {\n70:  ", "role": null}

